INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 1', '1', 'DE LAS DISPOSICIONES GENERALES', 'Este reglamento se expide en los términos de la Parte Cuarta, Sección Segunda, Capítulo Segundo, Título Cuarto del Libro Segundo del Código Civil del Estado de Guanajuato.', 'I', NULL, 0)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 2', '2', 'DE LAS DISPOSICIONES GENERALES', 'Además de los conceptos señalados en el Código Civil para el Estado de Guanajuato, para efectos de este reglamento se entenderá por: I. Administrador: Persona física, moral o institución que administre el condominio. II. Área Privativa o Unidad de Propiedad Exclusiva: El o los lotes que incluyen una vivienda susceptible de aprovechamiento individual sobre el cual se tiene un derecho singular y exclusivo de propiedad, y que se encuentran amparados y descritos dentro de la Declaratoria de Régimen de Propiedad en Condominio. III. Área Común: Aquellas que prestan un servicio y satisfacen necesidades colectivas, tales como jardines, calles interiores, estacionamientos de visitas, caseta de vigilancia, áreas de servicios, instalaciones de la alberca, y demás instalaciones generales que no se incluyen en el área privativa. IV. Código Civil: El Código Civil del Estado de Guanajuato. V. Condominio: Al inmueble identificado como Condominio Horizontal “VILLA CATANIA”, ubicado sobre vialidad Paseo Toscana, al interior del fraccionamiento “LA CANTERA 2”, localizado en el municipio de Celaya, Guanajuato. VI. Condómino: Las personas físicas o morales que sean titulares de los derechos sobre una propiedad exclusiva dentro del condominio. VII. CAD: Al Comité de Arquitectura y Diseño, que es el grupo de condóminos designados por la asamblea que, junto con el Administrador, serán los responsables para la aplicación de los lineamientos técnicos constructivos previstos en el presente ordenamiento. VIII. Copropiedad: El derecho irrenunciable perteneciente a varias personas pro indiviso (sin división). IX. Escritura Constitutiva: Al instrumento en el que conste la constitución formal del condominio materia del presente reglamento. X. La Asamblea: La asamblea general de condóminos. XI. Promotor: Persona moral que desarrolla el condominio. XII. Reglamento: El Reglamento de Construcción, Funcionamiento y Administración del Condominio “VILLA CATANIA”. XIII. Reglamento de Construcción: El Reglamento de Construcción para el Estado de Guanajuato y sus Municipios.', 'I', NULL, 1)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 3', '3', 'DE LAS DISPOSICIONES GENERALES', 'La constitución del régimen de propiedad en condominio es el acto jurídico formal que el propietario o propietarios de un inmueble, instrumentarán ante Notario Público declarando su voluntad de establecer esa modalidad de propiedad, para usar y disponer de él.', 'I', NULL, 2)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 4', '4', 'DE LAS DISPOSICIONES GENERALES', 'Este reglamento tiene como función principal establecer los derechos y obligaciones de cada uno de los condóminos, las modalidades del funcionamiento de los servicios del inmueble y las limitaciones en el uso de los bienes comunes y privativos.', 'I', NULL, 3)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 5', '5', 'DE LAS DISPOSICIONES GENERALES', 'El presente reglamento es de observancia obligatoria para todos los condóminos y aquellas personas que en arrendamiento o por cualquier otra figura jurídica habiten permanentemente o transitoriamente el condominio.', 'I', NULL, 4)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 6', '6', 'DE LAS DISPOSICIONES GENERALES', 'Cualquier modificación a la escritura constitutiva del Condominio sólo será por acuerdo unánime de los propietarios.', 'I', NULL, 5)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 7', '7', 'DE LAS DISPOSICIONES GENERALES', 'La modificación a éste Reglamento o la modificación o extinción voluntaria del Condominio requerirá el acuerdo de un mínimo del 75% de la representación del Condominio.', 'I', NULL, 6)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 8', '8', 'DE LAS DISPOSICIONES GENERALES', 'Todo inmueble sujeto al régimen de Condominio, deberán estar asegurados cuando menos contra los riesgos de terremoto, incendio y explosión. Si el Condominio sufriera algún daño total o parcial, el seguro contratado correrá a cargo de cada uno de los Condóminos en la proporción que corresponda a su propiedad exclusiva.', 'I', NULL, 7)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 9', '9', 'DE LAS DISPOSICIONES GENERALES', 'Cada condómino será copropietario del área común del condominio en proporción al valor de su área privativa que se determina en la escritura constitutiva.', 'I', NULL, 8)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 10', '10', 'DE LAS DISPOSICIONES GENERALES', 'Cada condómino podrá servirse de los bienes comunes y gozar de los servicios e instalaciones generales, conforme a su normal destino ordinario, sin restringir o hacer más oneroso el derecho de los demás, pues de hacerlo así, se hará responsable de los daños y perjuicios que con ello ocasione.', 'I', NULL, 9)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 11', '11', 'DE LAS DISPOSICIONES GENERALES', 'Aunque un condómino abandone sus derechos o renuncie a usar determinados bienes comunes, continuará sujeto a las obligaciones que imponen el Código Civil, la escritura constitutiva, el presente reglamento y los acuerdos válidamente tomados en asamblea.', 'I', NULL, 10)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 12', '12', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Todo condómino puede usar, gozar y disponer de su propiedad privada enajenándola, gravándola o arrendándola, con las limitaciones que establezcan las hipotecas sin necesidad del consentimiento de los demás condóminos.', 'II', NULL, 11)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 13', '13', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Cada condómino podrá hacer uso de las áreas comunes del condominio, y gozar de sus servicios e instalaciones comunes sin afectarlos, deteriorarlos, restringirlos o encareciendo alguno de ellos.', 'II', NULL, 12)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 14', '14', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Todo condómino tendrá derecho de recibir los servicios de apoyo, seguridad y promoción que se programen en beneficio del condominio a servirse de los bienes comunes e instalaciones generales conforme a su uso natural.', 'II', NULL, 13)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 15', '15', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los condóminos tendrán derecho a modificar el interior y la parte trasera de la vivienda que se ubique dentro de su respectiva área privativa, siempre y cuando no se afecten los bienes de uso común, ni la estructura, muros de carga ni otros elementos esenciales.', 'II', NULL, 14)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 16', '16', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'La casa habitación sujeta al Condominio y destinada al arrendamiento, el propietario deberá incluir en el contrato de arrendamiento una cláusula en donde el arrendatario se obligue a cumplir con las disposiciones del presente reglamento.', 'II', NULL, 15)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 17', '17', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'El condómino, arrendatario o cualquier otro cesionario del uso del área privativa, podrán convenir entre sí el pago de las cuotas de mantenimiento y demás obligaciones del condominio, sin embargo, el condómino seguirá siendo el responsable solidario frente al condominio.', 'II', NULL, 16)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 18', '18', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los condóminos están obligados a formar parte de la Asamblea y la Administración del condominio de acuerdo con el presente reglamento.', 'II', NULL, 17)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 19', '19', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Por ningún motivo se podrán instalar en las áreas privativas giros del tipo comercial, industrial o de servicios. Asimismo, se prohíbe tener sustancias peligrosas, insalubres o molestas.', 'II', NULL, 18)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 20', '20', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'De existir cajones de estacionamiento para visitantes, sólo podrán utilizarse para estacionar vehículos ligeros de uso familiar, que su tamaño no exceda las dimensiones indicadas dentro de la propia área. Queda prohibido el uso de los cajones de visitas como estacionamiento permanente de vehículos de condóminos.', 'II', NULL, 19)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 21', '21', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Ningún condómino podrá entorpecer las entradas hacia otras áreas privativas, ni la circulación de las calles internas, dejando en ellas objetos que dificulten el paso a personas o vehículos. Tampoco se podrán estacionar vehículos por fuera de las áreas destinadas para tal fin.', 'II', NULL, 20)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 22', '22', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Queda prohibido para cualquier condómino, el estacionar vehículos sobre las vialidades comunes del condominio; para ello las viviendas que se construyan dentro de las áreas privativas, deberán contar con su respectivo cajón de estacionamiento dentro de la misma.', 'II', NULL, 21)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 23', '23', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Queda prohibido realizar tendidos de ropa a la vista de los demás condóminos, debiéndose realizar dentro del patio de servicio con el que, en su caso, la vivienda cuente.', 'II', NULL, 22)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 24', '24', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Todo condómino está obligado a realizar el aseo y limpieza de su área privativa, depositando la basura o residuos que sean producto de la misma, en los lugares apropiados.', 'II', NULL, 23)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 25', '25', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'No se permite el ingreso de camiones de carga, pasajeros, vehículos pesados y todos aquellos que excedan las medidas de un vehículo de uso familiar con excepción de que su ingreso sea para realizar mudanzas o reparaciones autorizadas.', 'II', NULL, 24)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 26', '26', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los condóminos deberán cubrir las cuotas para gastos de administración, mantenimiento, conservación y operación de bienes y servicios comunes, acordados en Asamblea.', 'II', NULL, 25)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 27', '27', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los gastos de administración, mantenimiento, conservación y operación de bienes y servicios comunes; los sueldos, las prestaciones y gratificaciones del personal administrativo y de mantenimiento, se cubrirán con las cuotas que apruebe la Asamblea.', 'II', NULL, 26)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 28', '28', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'En caso de que el área privativa sea sujeta de venta, el propietario de la misma deberá de encontrarse al corriente de pago de sus respectivas cuotas para gastos de administración, mantenimiento, conservación y operación de bienes y servicios comunes, debiendo exhibir constancia de no adeudo emitida por el Administrador.', 'II', NULL, 27)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 29', '29', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Las viviendas localizadas dentro del condominio, no podrán ser destinadas a la ubicación de “casas de asistencia” o de cualquier otro uso que no signifique la vivienda unifamiliar.', 'II', NULL, 28)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 30', '30', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Es obligación de cada condómino el mantener en buen estado el área verde que en su caso se ubique al frente de su vivienda y que se encuentre contenida dentro de su respectiva área privativa.', 'II', NULL, 29)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 31', '31', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Aún en los casos en que el condómino no habite de manera inmediata su respectiva vivienda, no lo exime del cumplimiento de sus obligaciones, por lo que se deberá mantener al corriente en sus aportaciones y atender las disposiciones del presente reglamento.', 'II', NULL, 30)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 32', '32', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'La alberca instalada al interior del Condominio, constituye un objeto de propiedad común, y por tanto, los Condóminos gozan de igual derecho de uso conforme a su normal destino, siendo su uso regulado por el reglamento específico contenido en el Anexo A del presente.', 'II', NULL, 31)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 33', '33', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'El Administrador estará obligado a contratar los servicios de un profesional para la conservación y mantenimiento de la alberca en buen estado de servir. El Administrador tendrá la facultad de suspender el uso de la alberca cuando las condiciones higiénicas o de seguridad así lo requieran.', 'II', NULL, 32)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 34', '34', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los Condóminos asumen la responsabilidad por el uso que den a la alberca en lo personal, de su familia y en general de cualquier persona que bajo su autorización o la de su familia ingrese a las instalaciones.', 'II', NULL, 33)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 35', '35', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Queda prohibido colocar cualquier tipo de anuncios publicitarios al interior del Condominio, exceptuando los anuncios que promuevan la venta o renta de alguna de las viviendas, previa autorización de la asamblea a través del CAD.', 'II', NULL, 34)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 36', '36', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Queda prohibido el depositar basura o escombros en cualquiera de las áreas comunes contenidas dentro del condominio, que su uso específico no sea para tal fin.', 'II', NULL, 35)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 37', '37', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'No se permitirá la posesión de animales de naturaleza ruidosa, peligrosa, desagradable o nociva; asimismo y para el caso de los daños que pudiesen ocasionar dichos animales a terceros o a las instalaciones, serán cubiertos por el condómino dueño del animal.', 'II', NULL, 36)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 38', '38', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Los condóminos que cuenten con animales domésticos, deberán mantenerlos en todo momento dentro de su área privativa, quedando estrictamente prohibido sacarlos a las áreas comunes sin la correa o sujeción correspondiente y sin recoger sus desechos.', 'II', NULL, 37)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 39', '39', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Se encuentra prohibido realizar obras o reparaciones en horario nocturno, salvo los casos de fuerza mayor y previa aprobación por el Administrador, otorgada por escrito.', 'II', NULL, 38)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 40', '40', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Se prohíbe derribar o trasplantar árboles, así como cambiar el uso o naturaleza de las áreas verdes.', 'II', NULL, 39)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 41', '41', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Todo condómino está obligado a acatar las determinaciones que se acuerden en la asamblea, aun cuando éste no haya asistido a la misma.', 'II', NULL, 40)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 42', '42', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'El condómino tendrá la obligación de portar y mostrar al personal de seguridad del condominio, la tarjeta distintiva, para el control de acceso vehicular que en su caso, el administrador haya implementado.', 'II', 'Acuerdo de la Asamblea Extraordinaria del 24-abr-2024 (Administración 2023-2025, Rocha): se entregan únicamente DOS corbatines por domicilio; el tercero requiere acreditar residencia. Acuerdo retomado y ratificado en la 1ª Asamblea Ordinaria 2026 del 16-ene-2026 (Administración 2025-2027, Garcés) al sumar el registro digital en la app de la villa como complemento de identificación.', 41)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 43', '43', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Las viviendas contenidas dentro del condominio, deberán tener siempre a la vista su respectivo número oficial.', 'II', NULL, 42)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 44', '44', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Ningún condómino o persona ajena al condominio, podrá tener a la vista objetos personales, muebles, o cualquier otro objeto en la parte frontal de las viviendas.', 'II', NULL, 43)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 45', '45', 'DE LOS DERECHOS Y OBLIGACIONES DE LOS CONDÓMINOS', 'Todo condómino, tendrá la obligación de depositar en bolsa cerrada, los desperdicios domésticos debidamente separados en orgánicos e inorgánicos, que su vivienda produzca, en el o los contenedores destinados para tal fin.', 'II', NULL, 44)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 46', '46', 'DE LA ASAMBLEA DEL CONDOMINIO', 'La asamblea general de condóminos es el órgano supremo del condominio, y deberá celebrarse por lo menos una vez al año, y dentro de sus facultades tendrá la capacidad de nombrar y cambiar libremente al Administrador y aprobar las acciones propuestas por éste.', 'III', NULL, 45)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 47', '47', 'DE LA ASAMBLEA DEL CONDOMINIO', 'Las asambleas generales por su tipo podrán ser ordinarias y extraordinarias.', 'III', NULL, 46)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 48', '48', 'DE LA ASAMBLEA DEL CONDOMINIO', 'Las asambleas generales se regirán por las disposiciones de la Ley de Propiedad en Condominio de Inmuebles para el Estado de Guanajuato, particularmente sus artículos 24 y 28.', 'III', NULL, 47)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 49', '49', 'DE LA ASAMBLEA DEL CONDOMINIO', 'Las convocatorias para la celebración de asambleas generales se harán de acuerdo a lo dispuesto por la legislación aplicable, debiendo fijarse en lugar visible del condominio entre tres y diez días naturales antes de la fecha de celebración.', 'III', NULL, 48)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 50', '50', 'DE LA ASAMBLEA DEL CONDOMINIO', 'La asamblea general tendrá las siguientes facultades: I. Nombrar y remover al Administrador; II. Discutir y aprobar el presupuesto de gastos para el año siguiente; III. Aprobar las cuotas ordinarias y extraordinarias; IV. Resolver sobre las modificaciones al presente reglamento conforme al artículo 7; V. Las demás que le confiera la ley.', 'III', NULL, 49)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 51', '51', 'DE LA ASAMBLEA DEL CONDOMINIO', 'Se suspenderá a los condóminos su derecho a voto, conservando siempre el derecho a voz, previa notificación al interesado y la aprobación de la asamblea general, en los siguientes casos: I. Por la falta de pago de dos cuotas para los gastos de administración, mantenimiento, conservación y operación de bienes y servicios comunes; y II. Cuando por sentencia judicial o laudo administrativo debidamente ejecutoriado, se haya condenado al pago de daños a favor del condominio y éste no haya sido cubierto.', 'III', NULL, 50)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 52', '52', 'DEL ADMINISTRADOR', 'Los condóminos serán administrados por la persona física o moral que designe la asamblea general en los términos del Código Civil y de este reglamento, pudiendo o no ser algún condómino.', 'IV', NULL, 51)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 53', '53', 'DEL ADMINISTRADOR', 'El administrador podrá desempeñar su cargo en forma gratuita o bajo remuneración, quedando establecida dicha remuneración por parte de la asamblea.', 'IV', NULL, 52)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 54', '54', 'DEL ADMINISTRADOR', 'El administrador para tomar posesión de su cargo deberá otorgar fianza por la cantidad que fije la asamblea de condóminos que lo nombre.', 'IV', NULL, 53)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 55', '55', 'DEL ADMINISTRADOR', 'Para desempeñar el cargo de administrador se requerirá ser mayor de edad, contar con plena capacidad jurídica y no tener adeudos con el condominio.', 'IV', NULL, 54)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 56', '56', 'DEL ADMINISTRADOR', 'El primer administrador del condominio será designado por quien otorgue la escritura constitutiva.', 'IV', NULL, 55)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 57', '57', 'DEL ADMINISTRADOR', 'Corresponderá al administrador: I. Convocar a asamblea general en los términos establecidos en este reglamento; II. Llevar la contabilidad y los libros del condominio; III. Atender la operación adecuada y eficiente de las instalaciones y servicios generales; IV. Representar legalmente a los condóminos en los asuntos comunes; V. Cumplir y hacer cumplir el presente reglamento y los acuerdos de asamblea.', 'IV', NULL, 56)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 58', '58', 'DEL ADMINISTRADOR', 'Estarán a cargo del administrador, quien será responsable de su conservación y llevarlos al día, los libros de la administración que serán los siguientes: I. Libro de actas de asamblea; II. Libro de contabilidad; III. Libro de inventario de las cosas muebles de propiedad común.', 'IV', NULL, 57)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 59', '59', 'DEL ADMINISTRADOR', 'El administrador será el representante legal de los condóminos en todos los asuntos comunes relacionados con el condominio, sea que se promuevan a nombre o en contra de ellos, y tendrá las facultades generales para pleitos, cobranzas y actos de administración.', 'IV', NULL, 58)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 60', '60', 'DEL ADMINISTRADOR', 'El administrador queda expresamente facultado para contratar y renovar en nombre de los condóminos el seguro a que se refiere el artículo 1034 del Código Civil.', 'IV', NULL, 59)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 61', '61', 'DEL ADMINISTRADOR', 'El administrador tiene la obligación de cumplir con todas las obligaciones administrativas, federales o locales relativas al inmueble en su conjunto.', 'IV', NULL, 60)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 62', '62', 'DEL ADMINISTRADOR', 'Las medidas que tome y las disposiciones que dicte el administrador, dentro de sus facultades, serán obligatorias para todos los condóminos, a menos de que la asamblea las modifique o revoque.', 'IV', NULL, 61)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 63', '63', 'DEL ADMINISTRADOR', 'El administrador necesariamente será removido por incumplimiento de cualquiera de sus obligaciones o por ausencia que le impida el eficaz cumplimiento de las mismas.', 'IV', NULL, 62)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 64', '64', 'DE LAS CUOTAS DEL CONDOMINIO', 'Los condóminos están obligados incondicionalmente a cubrir puntualmente las cuotas que se señalan en éste capítulo, durante los primeros cinco días de cada mes, salvo que la Asamblea asuma una fecha distinta. La cuota ordinaria de mantenimiento vigente es de $750.00 (setecientos cincuenta pesos 00/100 M.N.) mensuales por unidad privativa, debiendo cubrirse adicionalmente la décima tercera cuota anual en los meses de enero a marzo de cada año.', 'V', 'Acuerdo de la 2ª Asamblea General Ordinaria del 25-abr-2025 (Administración 2023-2025, Rocha): se aprueba el incremento a $750.00 mensuales con 12 votos contra otras dos propuestas; se ratifica la 13ª cuota anual y los intereses de $100.00 mensuales a partir del 1º de abril si no se cubre. Vigente desde junio de 2025.', 63)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 65', '65', 'DE LAS CUOTAS DEL CONDOMINIO', 'Las cuotas para gastos de administración y mantenimiento, operación de bienes y servicios comunes del condominio, no estarán sujetas a compensación, excepciones personales ni ningún otro supuesto que pueda excusar su pago.', 'V', NULL, 64)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 66', '66', 'DE LAS CUOTAS DEL CONDOMINIO', 'Los fondos de mantenimiento y de reserva, en tanto no se utilicen, deberán invertirse en valores de inversión a la vista de mínimo riesgo, conservando la liquidez necesaria para solventar las obligaciones de corto plazo del condominio.', 'V', NULL, 65)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 67', '67', 'DE LAS CUOTAS DEL CONDOMINIO', 'Las cuotas que no sean cubiertas por los condóminos oportunamente en las fechas y bajo las formalidades establecidas en el artículo 64 de éste Reglamento, causarán intereses moratorios a una tasa del 10% mensual sobre el adeudo, mismos que deberán cubrirse junto con el principal antes de poder hacer uso de las áreas comunes y servicios. Se considera condómino moroso a quien acumule el equivalente a dos cuotas de mantenimiento vencidas o un saldo combinado (cuotas más multas) superior a $1,000.00 (mil pesos 00/100 M.N.).', 'V', 'Acuerdo de la 1ª Asamblea Extraordinaria del 24-abr-2024 (Administración Rocha): publicación mensual de la lista de morosos en el tablón y la app del condominio (incorporado al sistema digital en enero 2026). Acuerdo de la 2ª Asamblea Ordinaria del 22-may-2026 (Administración 2025-2027, Garcés): se baja el umbral de morosidad de $1,500 a $1,000 para efectos de restricción de servicios y acceso automatizado.', 66)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 68', '68', 'DE LAS CUOTAS DEL CONDOMINIO', 'Cuando se celebre un contrato traslativo de dominio con relación a algún área privativa, el condómino cedente deberá entregar al condómino cesionario una constancia de no adeudo, emitida por el Administrador. El Administrador colocará avisos en caseta de vigilancia y en la app respecto a las viviendas con adeudos, y notificará a los compradores potenciales.', 'V', 'Acuerdo de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): se refuerza la exigencia de carta de no adeudo en compraventas y se acuerda colocar letrero visible en caseta. El acuerdo se implementa de inmediato sin votación adicional por considerarse aplicación directa del Art. 28 vigente.', 67)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 69', '69', 'DE LAS CUOTAS DEL CONDOMINIO', 'Los condóminos pagarán las contribuciones locales y federales que les corresponda, tanto por lo que hace a su área privativa, como a la parte proporcional que le corresponda sobre los bienes comunes.', 'V', NULL, 68)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 70', '70', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Cualquier obra nueva que no sea construida por el promotor del condominio, así como cualquier ampliación, remodelación, demolición, innovación o similar, deberá ser aprobada conjuntamente por el CAD y por el Administrador.', 'VI', NULL, 69)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 71', '71', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Las áreas privativas no podrán ser subdivididas ni fusionadas bajo ninguna circunstancia y solamente se permitirá la edificación de una vivienda por cada lote.', 'VI', NULL, 70)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 72', '72', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Queda prohibida cualquier ampliación, remodelación, demolición, innovación o construcción de algún elemento o espacio arquitectónico al frente de la vivienda, incluyendo jardines y espacios visibles desde la vialidad.', 'VI', NULL, 71)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 73', '73', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Las viviendas contenidas dentro del condominio, podrán verse modificadas en su parte trasera únicamente, con algún tipo de construcción, ampliación, remodelación, demolición, innovación o similar, siempre con autorización previa del CAD.', 'VI', NULL, 72)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 74', '74', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Queda expresamente prohibida cualquier ampliación de vivienda hacia el frente y en la parte trasera, conforme a la normatividad por zonificación expedida por el Ayuntamiento.', 'VI', NULL, 73)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 75', '75', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'En caso de que el condómino requiera colocar en su vivienda antenas o instalaciones especiales, tales como equipos de aire acondicionado, calefacción, calentadores solares, etc., éstas deberán quedar en todo momento ocultas de tal manera que no sean visibles desde la vialidad del frente.', 'VI', NULL, 74)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 76', '76', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'No se podrán plantar árboles de altura mayor a 2.50 metros a menos de dos metros de la línea divisoria entre un área privativa y otra; asimismo toda vegetación contenida dentro de su propiedad deberá mantenerse podada.', 'VI', NULL, 75)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 77', '77', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'Queda prohibido que el condómino realice obras sobre su respectiva área privativa, que afecte la estructura de la vivienda de algún otro condómino, o de alguna de las áreas comunes del condominio.', 'VI', NULL, 76)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 78', '78', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'No se permite la apertura de hueco, ventana o puerta al exterior del condominio.', 'VI', NULL, 77)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 79', '79', 'DE LAS LIMITANTES DE DISEÑO Y CONSTRUCCIÓN', 'En caso de ampliación, la pintura a utilizarse como acabado final sobre la fachada posterior deberá ser exclusivamente del tono cromático que se haya manejado en el prototipo original tipo de la vivienda.', 'VI', NULL, 78)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 80', '80', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'En caso de que algún condómino pretenda realizar alguno de los trabajos citados dentro del artículo 70 del presente documento, y previo a que éste reciba su respectivo visto bueno de procedencia, deberá presentar al CAD y al Administrador el proyecto ejecutivo correspondiente.', 'VII', NULL, 79)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 81', '81', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Todos los trabajos de construcción deberán de realizarse en estricto apego a los planos autorizados tanto por el CAD en conjunto con el administrador, y en caso de que el proyecto constructivo lo amerite, contar con las autorizaciones municipales correspondientes.', 'VII', NULL, 80)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 82', '82', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Todas aquellas obras que permanezcan suspendidas por el condómino, deberán contar con sus respectivos materiales de construcción dentro de la vivienda.', 'VII', NULL, 81)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 83', '83', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Mientras dure la obra, será indispensable que se encuentre a la vista en todo momento, la placa acrílica que en su caso haya sido otorgada por la autoridad municipal competente.', 'VII', NULL, 82)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 84', '84', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Es responsabilidad y obligación del condómino, el asegurarse que los trabajadores que laboren dentro de su predio, esté o no en proceso de construcción, cuenten con la debida seguridad social.', 'VII', NULL, 83)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 85', '85', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Será obligación del condómino el mantener un orden y limpieza en sus materiales de construcción, así como respetar las condiciones físicas naturales tanto de los predios vecinos.', 'VII', NULL, 84)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 86', '86', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Es obligación del condómino y del constructor, así como de los trabajadores que laboren en la obra, permitir el acceso a los integrantes de la autoridad municipal o su personal autorizado para inspeccionar sus avances.', 'VII', NULL, 85)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 87', '87', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Todas las construcciones deberán respetar el horario de trabajo permitido para laborar en obra y al que deberán sujetarse tanto contratistas como proveedores, el cual será de lunes a viernes de 7:00 a 19:00 hrs y sábados de 7:00 a 14:00 hrs.', 'VII', NULL, 86)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 88', '88', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'De ser necesario, únicamente se permitirá la estancia permanente de un vigilante, dentro de las construcciones en proceso, sin acompañantes ni animales domésticos.', 'VII', NULL, 87)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 89', '89', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Todos los empleados, proveedores y personal involucrado en la construcción de las obras, deberán cumplir con todas y cada una de las disposiciones de seguridad descritas dentro del presente reglamento.', 'VII', NULL, 88)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 90', '90', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Las cuotas de mantenimiento no cubrirán ninguno de los daños a las áreas comunes, infraestructura del condominio o hacia el resto de los condóminos, que pudieran derivarse durante el proceso de construcción.', 'VII', NULL, 89)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 91', '91', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Será necesario que la obra cuente con la señalización adecuada, advirtiendo todo tipo de riesgos.', 'VII', NULL, 90)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 92', '92', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Queda prohibido que el personal de trabajo de las obras en proceso de construcción utilice alguno de los predios vecinos o la vía pública para solventar sus necesidades biológicas.', 'VII', NULL, 91)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 93', '93', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'En el área de construcción deberá existir un depósito exclusivo para basura (nunca escombro), éste podrá ser un tambo metálico de un volumen que no exceda los 200 litros.', 'VII', NULL, 92)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 94', '94', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Las obras en construcción deberán, en lo posible mantenerse libres de desperdicios o sobrantes de materiales de construcción (escombros).', 'VII', NULL, 93)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 95', '95', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'Queda estrictamente prohibido el realizar mezclas o revoltura de cualquier tipo de material sobre banqueta, guarniciones o arroyo de vialidad.', 'VII', NULL, 94)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 96', '96', 'DE LA SEGURIDAD Y CONTROL DE OBRA', 'En caso de utilizarse concreto premezclado y vaciado con camión-bomba, deberá tomar las previsiones necesarias para evitar que los desperdicios del mismo dañen banquetas, guarniciones o arroyo de vialidad.', 'VII', NULL, 95)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97', '97', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'El orden, la seguridad y convivencia entre condóminos, se regirá por las siguientes normas: 1. Los condóminos y visitantes están obligados a informar al cuerpo de vigilancia, a las oficinas administrativas, a la administración del condominio o a las autoridades competentes, sobre cualquier irregularidad o desacato a las normas que en adelante se mencionan. 2. Los condóminos deberán considerar las medidas necesarias a fin de que los ruidos producidos por aparatos de sonido, instrumentos musicales, animales domésticos o ruidos de cualquier otra naturaleza no puedan ser escuchados desde la vía pública o desde cualquier otra propiedad vecina. 3. Queda estrictamente prohibido el ingreso de vehículos que disturben el orden público o que generen ruidos molestos para los condóminos. 4. Todos los vehículos que circulen dentro de las vialidades del condominio están obligados a respetar los señalamientos viales horizontales y verticales, así como acatar lo dispuesto por la Ley de Tránsito del Estado de Guanajuato. 5. El condómino que carezca de control automático de acceso (en caso de instalarse), tendrá la obligación de acatar las normas de seguridad establecidas por el protocolo de seguridad, en lo referente al control de acceso que a la fecha la Asamblea determine. 6. El condómino queda obligado a informar oportunamente al administrador del condominio o a la Asamblea, sobre los traslados de dominio respecto de sus propiedades, para efectos administrativos y de seguridad.', 'VIII', NULL, 96)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 bis', '97 bis', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'El Administrador publicará, en el tablón de anuncios físico de la caseta y en la app oficial del condominio, la lista de condóminos con cuotas de mantenimiento pendientes y multas vigentes, a más tardar el primer día hábil de cada mes.', 'VIII', 'Acuerdo de la 1ª Asamblea Extraordinaria del 24-abr-2024 (Administración Rocha): aprobado por unanimidad. Incluido como Art. 42 ter en el borrador ''Reglamento General Unificado'' de julio 2025. Esta versión lo reubica al Capítulo VIII por afinidad temática (seguridad, vigilancia y convivencia).', 97)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 ter', '97 ter', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'El servicio de vigilancia contratado por el condominio mantendrá una plantilla fija de guardias previamente identificados y capacitados en los protocolos de la villa. El Administrador acordará con el proveedor del servicio la rotación mínima de personal y el conocimiento previo del condominio por parte de cada elemento.', 'VIII', 'Acuerdo de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): se solicitó al proveedor mantener tres guardias fijos identificados. Nota de la 2ª Asamblea Ordinaria del 22-may-2026: el acuerdo de revisión obligatoria de cajuelas mencionado en la 1ª Asamblea no se incorpora a este reglamento por no haberse implementado operativamente; en su lugar se priorizó el esquema de plantilla fija que sí ha funcionado.', 98)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 quater', '97 quater', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'El condominio reconoce a la app oficial de Villa Catania como canal formal de comunicación, registro de visitas, reservación de áreas comunes, levantamiento de incidencias, consulta de adeudos y rendición de cuentas. El uso del sistema es obligatorio para todos los condóminos, y la condición de los servicios (recolección de basura, jardinería al frente, accesos automatizados y reservaciones) se sujetará al estatus de pago registrado en el sistema.', 'VIII', 'Acuerdo de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): aprobado por unanimidad de los 32 condóminos presentes. La app no genera costo para los condóminos en su fase actual.', 99)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 quinquies', '97 quinquies', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'Toda mudanza que se realice en alguna unidad privativa (sea de entrada o salida) requiere autorización previa del Administrador. La autorización solo se otorgará cuando el condómino solicitante acredite estar al corriente en cuotas de mantenimiento y multas, y haya registrado la operación en la app oficial del condominio.', 'VIII', 'Acuerdo de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): se acordó por consenso implementar de inmediato, sin votación adicional, por tratarse de aplicación directa del régimen de cobranza y control de acceso ya vigente.', 100)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 sexies', '97 sexies', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'Los cajones de estacionamiento de visitas son de uso exclusivo para visitantes y por un periodo no mayor a 24 horas continuas. Queda prohibido su uso como estacionamiento permanente por condóminos o inquilinos. Las incidencias se reportarán con evidencia fotográfica a través de la app oficial. Los vehículos abandonados serán notificados al propietario; en caso de no atención dentro del plazo señalado por el Administrador, se reportarán a tránsito municipal.', 'VIII', 'Acuerdo de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): aprobado por consenso. Refuerza y operacionaliza el Art. 20 original.', 101)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 septies', '97 septies', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'Queda prohibida la entrada al condominio de vehículos motorizados de dos ruedas pertenecientes a servicios de mensajería, paquetería y entrega de comida a domicilio (Rappi, Uber Eats, DiDi Food, motoexpresos y similares). Las entregas se realizarán desde la caseta de vigilancia, debiendo el condómino acudir a recibir o autorizar la entrega a pie por el personal de vigilancia. Se exceptúan los casos puntuales debidamente notificados y registrados al Administrador para personas con discapacidad, adultos mayores que vivan solos, o servicios médicos o farmacéuticos de urgencia.', 'VIII', 'Acuerdo de la 2ª Asamblea General Ordinaria del 22-may-2026 (Administración Garcés): APROBADO con 16 votos a favor y 12 en contra, conforme al Registro Oficial de Votaciones de esa sesión. Aplicación inmediata una vez publicada la modificación.', 102)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 97 octies', '97 octies', 'DE LA SEGURIDAD, VIGILANCIA Y CONVIVENCIA', 'La velocidad máxima dentro de las vialidades del condominio es de 20 km/h. El Administrador queda facultado para implementar boyas, topes y señalización adicional cuando lo considere necesario para la seguridad de niños y adultos mayores. Las cámaras instaladas en accesos podrán utilizarse como evidencia para sancionar infracciones de tránsito interno.', 'VIII', 'Boyas de tránsito: aprobadas en la plataforma digital previo a la 2ª Asamblea Ordinaria 22-may-2026. La cotización de topes adicionales y nueva señalización quedó pendiente de cierre de votación en la app en la misma sesión (Administración Garcés).', 103)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 98', '98', 'DEL SEGURO, DESTRUCCIÓN, RUINA Y RECONSTRUCCIÓN DEL CONDOMINIO', 'Para el caso de destrucción, ruina y reconstrucción del condominio por terremoto, incendio, explosión o cualquier otra eventualidad, se estará a lo dispuesto en la Parte Séptima, Sección Segunda, Capítulo Segundo, Título Cuarto del Libro Segundo del Código Civil de Guanajuato.', 'IX', NULL, 104)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 99', '99', 'DE LAS CONTROVERSIAS Y SANCIONES', 'El condómino u ocupante que no cumpla con las obligaciones a su cargo será responsable de los daños y perjuicios que cause a los demás. Sin perjuicio de lo anterior, si el infractor fuese un ocupante no condómino, el administrador deberá demandarle, llamando a juicio al condómino, la desocupación del inmueble, previo acuerdo de las tres cuartas partes de los demás condóminos.', 'X', NULL, 105)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 100', '100', 'DE LAS CONTROVERSIAS Y SANCIONES', 'El condómino que reiteradamente no cumpla con sus obligaciones podrá ser condenado judicialmente a vender sus derechos en pública subasta. Para el ejercicio de esta acción por el administrador, deberá preceder la resolución de las tres cuartas partes de los condóminos restantes.', 'X', NULL, 106)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 101', '101', 'DE LAS CONTROVERSIAS Y SANCIONES', 'Cuando no puedan reunirse las proporciones que establece este Reglamento para tomar acuerdo por la asamblea, deberá someterse la controversia a la decisión judicial.', 'X', NULL, 107)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 101 bis', '101 bis', 'DE LAS CONTROVERSIAS Y SANCIONES', 'El tabulador de multas por infracciones al presente reglamento se aplicará bajo un esquema progresivo por número de ocurrencia. El monto señalado para cada infracción corresponde a la PRIMERA ocurrencia del condómino. Las ocurrencias posteriores se sancionarán multiplicando el monto base por el número de ocurrencia, conforme a la siguiente fórmula:', 'X', 'Tabulador implementado y aplicado por la Administración Garcés a partir de septiembre 2025. Validado operativamente en la 1ª Asamblea Ordinaria del 16-ene-2026 (43 multas formalizadas con evidencia y registro digital, $17,640 acumulados). Presentado en la 2ª Asamblea Ordinaria del 22-may-2026 sin objeciones. El esquema progresivo se incorpora formalmente en mayo de 2026 como criterio administrativo de aplicación, conforme a las facultades de cobranza del Administrador previstas en los Arts. 57 y 59 de este reglamento. Multa por ocurrencia N  =  Monto base × N Donde N es el número consecutivo de ocurrencias acumuladas por el mismo condómino para el mismo tipo de infracción. El contador NO se reinicia (es acumulado de manera permanente desde la entrada en vigor del tabulador en septiembre de 2025) y NO tiene tope superior. La aplicación del esquema progresivo es automática a través de la app oficial del condominio, y la notificación se envía al condómino infractor en cada ocasión. Infracción Monto base 1ª (MXN) Reincidencia (N-ésima) Mal uso de estacionamiento de visitas (Art. 20 y 97 sexies) $300 $300 × N Mascotas sueltas o sin recoger desechos (Art. 38) $250 $250 × N Ruido excesivo / molestias por sonido (Art. 97 fr. II) $500 $500 × N Mal uso de amenidades (Alberca / Terraza) $400 $400 × N Deterioro de fachada o falta de mantenimiento visible $1,000 $1,000 × N Ingreso de motoservicios prohibido (Art. 97 septies) $300 $300 × N Ejemplo aplicado al mal uso de estacionamiento de visitas (monto base $300): Ocurrencia Cálculo Multa aplicada 1ª ocurrencia $300 × 1 $300 2ª ocurrencia $300 × 2 $600 3ª ocurrencia $300 × 3 $900 4ª ocurrencia $300 × 4 $1,200 5ª ocurrencia $300 × 5 $1,500 N-ésima ocurrencia $300 × N Sin tope Las multas se cargarán al estado de cuenta del condómino en la app oficial inmediatamente después de validada la evidencia por el Administrador. La acumulación de adeudos por multas se rige por el Art. 67 (umbral de morosidad acumulado en $1,000), pudiendo activarse las restricciones de servicio y de acceso automatizado correspondientes. La condonación o reducción de una multa específica solo procederá por acuerdo expreso del Comité, debidamente registrado en la bitácora administrativa, cuando exista causa justificada acreditada por el condómino.', 108)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 102', '102', 'TRANSITORIOS', 'Lo no previsto en el presente reglamento se resolverá de acuerdo al Código Civil del Estado de Guanajuato, a la Ley de Propiedad en Condominio de Inmuebles para el Estado de Guanajuato y, en su defecto, por acuerdo de la asamblea general de condóminos.', 'XI', NULL, 109)
ON CONFLICT (colonia_id, num) DO UPDATE SET texto = EXCLUDED.texto, titulo = EXCLUDED.titulo, capitulo = EXCLUDED.capitulo, bitacora = EXCLUDED.bitacora, orden = EXCLUDED.orden, articulo = EXCLUDED.articulo;

INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Artículo 102 bis', '102 bis', 'TRANSITORIOS', 'El Art. 42 bis previsto en el borrador ''Reglamento General Unificado'' de julio de 2025 (control de acceso mediante TAGs y barrera vehicular) queda formalmente eliminado de este reglamento, por no haberse implementado en ningún momento durante la Administración 2023-2025 que lo propuso. La adopción de un sistema RFID con semáforo aprobada en la 2ª Asamblea General Ordinaria del 22-may-2026 (Administración Garcés) queda en estatus de acuerdo de asamblea pendiente de instalación; se incorporará al cuerpo del reglamento como artículo formal una vez que el sistema esté operativo y se valide su funcionamiento en una asamblea posterior.', 'XI', 'Eliminación de Art. 42 bis (TAGs): instruida por la Administración Garcés en mayo de 2026 con base en evidencia de no implementación durante 18 meses. Aprobación del RFID y modificación operativa del Art. 42 (foto sin retención de identificación): 2ª Asamblea General Ordinaria del 22-may-2026, conforme al Registro Oficial de Votaciones (APROBADO). ANEXO A REGLAMENTO PARA INGRESO A LA ALBERCA Reglamento elaborado y firmado en septiembre de 2024 por la Administración 2023-2025 (Rocha). Modificado en la 2ª Asamblea General Ordinaria del 25-abr-2025: la llave para uso de la alberca solo se entrega al condómino que presente el tarjetón del mes en curso y realice el registro en caseta. Operación complementaria validada por la Administración 2025-2027 (Garcés) tras la rehabilitación de la alberca en marzo de 2026. 1. El uso de las instalaciones de la Alberca es para los Condóminos propietarios y/o poseedores que se encuentren al corriente en sus cuotas de mantenimiento, conforme al Art. 67 del Reglamento General. 2. La llave de acceso se entregará únicamente al condómino que presente su tarjetón del mes en curso y realice su registro en caseta. Dicho condómino será responsable de cumplir con este reglamento durante todo el periodo de uso, incluyendo a sus invitados. 3. No se permiten actos que atenten contra la moral y las buenas costumbres. 4. Uso obligatorio de traje de baño, sin excepción de edad. Las fibras de otras telas dañan el sistema de filtrado. 5. Prohibido ingresar mascotas. 6. Los menores de edad siempre deberán estar supervisados por un adulto responsable. 7. El horario de uso es de 8:00 a 20:00 hrs. 8. Prohibido ingresar alimentos, bebidas alcohólicas y de cualquier otro tipo, así como fumar dentro del área de la alberca. 9. Prohibido sustraer o reubicar el mobiliario del área. 10. El número máximo de personas dentro de la alberca por casa no debe ser mayor a 5; el uso es compartido con otras casas. 11. Todos los propietarios, poseedores e invitados están obligados a respetar y vigilar el cumplimiento de este reglamento. 12. Los daños o destrozos causados a las instalaciones y equipo serán cobrados al condómino responsable. 13. Al terminar el uso, deberá colocarse la cubierta a la alberca, cerrar y colocar candado, y dejar los baños cerrados. 14. La violación a este reglamento será sancionada conforme al tabulador del Art. 101 bis (mal uso de amenidades: $400). RECUERDA QUE LAS INSTALACIONES SON TUYAS, CUÍDALAS. ANEXO B REGLAMENTO PARA USO DE TERRAZA VILLA CATANIA Reglamento elaborado y firmado en abril de 2025 por la Administración 2023-2025 (Rocha). Modificado por acuerdos de la 1ª Asamblea Ordinaria del 16-ene-2026 (Administración Garcés): se establece cuota de recuperación de $3,000 MXN por evento, depósito en garantía de igual monto, horario límite 22:00 hrs y periodo de prueba de 6 meses para evaluar el esquema. 1. El uso de las instalaciones de la Terraza es exclusivo de los condóminos propietarios y/o poseedores del Clúster Villa Catania que se encuentren al corriente en sus cuotas de mantenimiento. 2. El espacio de Terraza NO es para fiestas en sentido amplio; cualquier evento (reunión privada, festejo) requiere la reserva en la app oficial, el pago de la cuota de recuperación de $3,000 MXN y el depósito en garantía de $3,000 MXN, que se reintegra una vez verificado que no hay daños y que las instalaciones se entregaron limpias. 3. Está prohibido realizar eventos sociales en jardines y demás áreas comunes distintas a la Terraza. 4. Horarios autorizados para uso ordinario (no eventos): lunes a jueves y domingo de 8:00 a 23:00 hrs; viernes y sábado de 8:00 a 24:00 hrs. Horario límite para eventos reservados: 22:00 hrs, conforme al acuerdo de la 1ª Asamblea Ordinaria 16-ene-2026. 5. Si después del horario establecido continúan personas en la Terraza, se solicitará la intervención de Seguridad Ciudadana. 6. La música deberá escucharse con volumen moderado, sin molestar a los demás condóminos. 7. Queda prohibido apartar sillas y mesas del área de la Terraza para uso fuera de ella. 8. Después de usar las instalaciones y el asador, deberán dejarse limpias, con el carbón apagado y la basura en bolsas amarradas. 9. Dejar paredes y áreas libres de pegamento, globos y adornos. 10. No se permiten actos que atenten contra la moral y las buenas costumbres. 11. No se permite instalar inflables en el área de Terraza y jardines. 12. El aforo máximo en la Terraza es de 25 personas. 13. Quien incumpla algún punto será acreedor a la multa correspondiente conforme al Art. 101 bis (mal uso de amenidades: $400) y, en caso de daños, al cargo del depósito en garantía y, de ser insuficiente, el cobro adicional al condómino responsable. 14. Por las noches las luces deberán permanecer encendidas durante el uso y apagarse al terminar. 15. Los daños o destrozos causados a las instalaciones y equipo serán cobrados al condómino responsable. 16. Al terminar el uso, apagar luces, entregar llaves a caseta y dejar baños cerrados. RECUERDA QUE LAS INSTALACIONES SON TUYAS, CUÍDALAS. ANEXO C BITÁCORA CONSOLIDADA DE ACUERDOS Y PROYECTOS PENDIENTES DE INTEGRAR Los siguientes acuerdos de asamblea fueron aprobados pero permanecen como acuerdos operativos pendientes de instalación, ejecución o validación. Una vez consolidados, se incorporarán como artículos formales en una próxima reforma del reglamento conforme al Art. 7. Acuerdo Origen Estatus / Próximo paso RFID con semáforo en accesos vehiculares 2ª Asamblea Ord. 22-may-2026 (Garcés) — APROBADO Pendiente de instalación. Modifica operativamente el Art. 42 (no se retendrá identificación, solo se tomará foto). Se integrará como artículo formal al cuerpo del reglamento una vez puesto en operación y validado en asamblea. Paneles solares para áreas comunes 2ª Asamblea Ord. 22-may-2026 (Garcés) — APROBADO Pendiente de cotización final y ejecución. Una vez instalados, podrá considerarse incorporar artículo sobre uso, mantenimiento y reposición. Cuota de recuperación por evento en Terraza ($3,000) 1ª Asamblea Ord. 16-ene-2026 (Garcés) — APROBADO 15/29 Periodo de prueba de 6 meses (jul-2026 término del periodo). Tras la evaluación, se valorará ratificación, ajuste o reversión. Protocolización del Comité 2025-2027 ante notario 1ª Asamblea Ord. 16-ene-2026 (Garcés) — APROBADO Pendiente de ejecución. Compromiso mínimo de permanencia 2 años. Habilita acciones legales formales de cobranza. Restricción de mascotas en áreas comunes 1ª Asamblea Ord. 16-ene-2026 (Garcés) — PROPUESTA En votación abierta en la app. Pendiente cierre y formalización en próxima asamblea ordinaria. Rehabilitación de alberca con acabado chukum 1ª Asamblea Ord. 16-ene-2026 (Garcés) — Cotizado Rehabilitación parcial ejecutada (marzo 2026, $10,896). Pendiente ejecución del acabado tipo chukum sujeto a fondo extraordinario. Negociación deuda Casa 114 2ª Asamblea Ord. 22-may-2026 (Garcés) — RESUELTO Decisión ejecutiva del Presidente (depósito materializado antes de la asamblea por $30,000 MXN, ratificada por unanimidad en la sesión). Recursos destinados contablemente al fondo del proyecto RFID. Carta de no adeudo emitida. Aprobación de la versión consolidada Conforme al Art. 7 del presente reglamento, la modificación del mismo requiere el acuerdo de un mínimo del 75% de la representación del condominio. La presente versión consolidada se publica como documento de trabajo, y será sometida a votación en asamblea para adquirir fuerza formal de reforma. Mientras tanto, los artículos y anexos que provienen de acuerdos válidamente votados en asamblea (identificados con su bitácora) son obligatorios para los condóminos en los términos del Art. 41 del propio reglamento, que establece: “Todo condómino está obligado a acatar las determinaciones que se acuerden en la asamblea, aun cuando éste no haya asistido a la misma.” Celaya, Guanajuato, a 24 de mayo de 2026. ASOCIACIÓN DE COLONOS DE VILLA CATANIA, A.C. COMITÉ DE ADMINISTRACIÓN 2025-2027 Juan Garcés Castillo Presidente — Casa 128 Gerardo Pérez Magaña Secretario — Casa 152 Araceli Martínez Santander Tesorera — Casa 158 Miguel Rivera Vocal — Casa 101 Sergio Calderón Vocal — Casa 102 Martha Lara Vocal — Casa 140', 110)
