INSERT INTO vecino.reglamento (colonia_id, articulo, num, titulo, texto, capitulo, bitacora, orden)
VALUES ('ce43b59c-529b-4960-8dd7-d975e43ac2fb', 'Anexo A', 'Anexo A', 'Reglamento para Ingreso a la Alberca', '📌 Bitácora: Reglamento elaborado y firmado en septiembre de 2024 por la Administración 2023-2025 (Rocha). Modificado en la 2ª Asamblea General Ordinaria del 25-abr-2025: la llave para uso de la alberca solo se entrega al condómino que presente el tarjetón del mes en curso y realice el registro en caseta. Operación complementaria validada por la Administración 2025-2027 (Garcés) tras la rehabilitación de la alberca en marzo de 2026. 1. El uso de las instalaciones de la Alberca es para los Condóminos propietarios y/o poseedores que se encuentren al corriente en sus cuotas de mantenimiento, conforme al Art. 67 del Reglamento General. 2. La llave de acceso se entregará únicamente al condómino que presente su tarjetón del mes en curso y realice su registro en caseta. Dicho condómino será responsable de cumplir con este reglamento durante todo el periodo de uso, incluyendo a sus invitados. 3. No se permiten actos que atenten contra la moral y las buenas costumbres. 4. Uso obligatorio de traje de baño, sin excepción de edad. Las fibras de otras telas dañan el sistema de filtrado. 5. Prohibido ingresar mascotas. 6. Los menores de edad siempre deberán estar supervisados por un adulto responsable. 7. El horario de uso es de 8:00 a 20:00 hrs. 8. Prohibido ingresar alimentos, bebidas alcohólicas y de cualquier otro tipo, así como fumar dentro del área de la alberca. 9. Prohibido sustraer o reubicar el mobiliario del área. 10. El número máximo de personas dentro de la alberca por casa no debe ser mayor a 5; el uso es compartido con otras casas. 11. Todos los propietarios, poseedores e invitados están obligados a respetar y vigilar el cumplimiento de este reglamento. 12. Los daños o destrozos causados a las instalaciones y equipo serán cobrados al condómino responsable. 13. Al terminar el uso, deberá colocarse la cubierta a la alberca, cerrar y colocar candado, y dejar los baños cerrados. 14. La violación a este reglamento será sancionada conforme al tabulador del Art. 101 bis (mal uso de amenidades: $400).', 'Anexos', NULL, 111)
